     1→import { Toaster } from "@/components/ui/toaster";
     2→import { Toaster as Sonner } from "@/components/ui/sonner";
     3→import { TooltipProvider } from "@/components/ui/tooltip";
     4→import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
     5→import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
     6→import { TeamAuthProvider, useTeamAuth } from "@/contexts/TeamAuthContext";
     7→import { AdminAuthProvider } from "@/contexts/AdminAuthContext";
     8→import { ProtectedRoute } from "@/components/ProtectedRoute";
     9→import { AdminProtectedRoute } from "@/components/AdminProtectedRoute";
    10→import Login from "./pages/Login";
    11→import Signup from "./pages/Signup";
    12→import Dashboard from "./pages/Dashboard";
    13→import TrackSelection from "./pages/TrackSelection";
    14→import Leads from "./pages/Leads";
    15→import AdminLogin from "./pages/AdminLogin";
    16→import AdminSignup from "./pages/AdminSignup";
    17→import Admin from "./pages/Admin";
    18→import AdminDisplay from "./pages/AdminDisplay";
    19→import NotFound from "./pages/NotFound";
    20→
    21→const queryClient = new QueryClient();
    22→
    23→function RootRedirect() {
    24→  const { team, loading } = useTeamAuth();
    25→  
    26→  if (loading) {
    27→    return (
    28→      <div className="min-h-screen flex items-center justify-center bg-background">
    29→        <div className="w-8 h-8 border-4 border-foreground border-t-transparent animate-spin" />
    30→      </div>
    31→    );
    32→  }
    33→  
    34→  if (!team) return <Navigate to="/signup" replace />;
    35→  if (!team.track) return <Navigate to="/track-selection" replace />;
    36→  return <Navigate to="/dashboard" replace />;
    37→}
    38→
    39→const App = () => (
    40→  <QueryClientProvider client={queryClient}>
    41→    <TooltipProvider>
    42→      <Toaster />
    43→      <Sonner />
    44→      <BrowserRouter>
    45→        <AdminAuthProvider>
    46→          <TeamAuthProvider>
    47→            <Routes>
    48→              <Route path="/" element={<RootRedirect />} />
    49→              <Route path="/login" element={<Login />} />
    50→              <Route path="/signup" element={<Signup />} />
    51→              <Route path="/track-selection" element={
    52→                <ProtectedRoute>
    53→                  <TrackSelection />
    54→                </ProtectedRoute>
    55→              } />
    56→              <Route path="/dashboard" element={
    57→                <ProtectedRoute>
    58→                  <Dashboard />
    59→                </ProtectedRoute>
    60→              } />
    61→              <Route path="/leads" element={
    62→                <ProtectedRoute>
    63→                  <Leads />
    64→                </ProtectedRoute>
    65→              } />
    66→              {/* Admin Routes */}
    67→              <Route path="/admin/login" element={<AdminLogin />} />
    68→              <Route path="/admin/signup" element={<AdminSignup />} />
    69→              <Route path="/admin" element={
    70→                <AdminProtectedRoute>
    71→                  <Admin />
    72→                </AdminProtectedRoute>
    73→              } />
    74→              <Route path="/admin/display" element={
    75→                <AdminProtectedRoute>
    76→                  <AdminDisplay />
    77→                </AdminProtectedRoute>
    78→              } />
    79→              {/* ADD ALL CUSTOM ROUTES ABOVE THE CATCH-ALL "*" ROUTE */}
    80→              <Route path="*" element={<NotFound />} />
    81→            </Routes>
    82→          </TeamAuthProvider>
    83→        </AdminAuthProvider>
    84→      </BrowserRouter>
    85→    </TooltipProvider>
    86→  </QueryClientProvider>
    87→);
    88→
    89→export default App;
    90→

