     1→import { useState, useEffect, useMemo, useRef } from 'react';
     2→import { ChevronDown, ChevronRight, Check, Info } from 'lucide-react';
     3→import { cn } from '@/lib/utils';
     4→import { TaskInputItem } from './TaskInputItem';
     5→import { AIGeneratedTaskItem } from './AIGeneratedTaskItem';
     6→import confetti from 'canvas-confetti';
     7→import type { SprintTask } from '@/data/sprintTasks';
     8→import type { Phase1Data } from '@/hooks/useAIGeneration';
     9→
    10→interface PhaseChecklistProps {
    11→  phase: string;
    12→  label: string;
    13→  description: string;
    14→  phaseNote?: string;
    15→  tasks: SprintTask[];
    16→  teamId: string;
    17→  currentPhase: string;
    18→  completedTasks: Set<string>;
    19→  taskContents: Map<string, string | null>;
    20→  phase1Data: Phase1Data;
    21→  phase1Complete: boolean;
    22→  missingPhase1Tasks: string[];
    23→  onTaskSave: (taskKey: string, content: string, phase: string) => Promise<void>;
    24→}
    25→
    26→const phaseColorClasses: Record<string, string> = {
    27→  phase_1: 'phase-1',
    28→  phase_2: 'phase-2',
    29→  phase_3: 'phase-3',
    30→  phase_4: 'phase-4',
    31→};
    32→
    33→const phaseOrder = ['waiting', 'phase_1', 'phase_2', 'phase_3', 'phase_4', 'completed'];
    34→
    35→const taskTitleMap: Record<string, string> = {
    36→  p1_problem: 'Problem Statement',
    37→  p1_solution: 'Solution',
    38→  p1_customer: 'Target Customer',
    39→  a1_workflow: 'Workflow Description',
    40→  a1_pain_points: 'Pain Points',
    41→  a1_tools: 'Tools Involved',
    42→  a1_time_spent: 'Time Spent',
    43→};
    44→
    45→export function PhaseChecklist({
    46→  phase,
    47→  label,
    48→  description,
    49→  phaseNote,
    50→  tasks,
    51→  teamId,
    52→  currentPhase,
    53→  completedTasks,
    54→  taskContents,
    55→  phase1Data,
    56→  phase1Complete,
    57→  missingPhase1Tasks,
    58→  onTaskSave,
    59→}: PhaseChecklistProps) {
    60→  const [isOpen, setIsOpen] = useState(false);
    61→  const prevCompletedCount = useRef(0);
    62→
    63→  const currentIndex = phaseOrder.indexOf(currentPhase);
    64→  const phaseIndex = phaseOrder.indexOf(phase);
    65→  const isActive = currentPhase === phase;
    66→  const isPast = currentIndex > phaseIndex;
    67→  const isFuture = currentIndex < phaseIndex;
    68→
    69→  // Auto-expand current phase
    70→  useEffect(() => {
    71→    if (isActive) {
    72→      setIsOpen(true);
    73→    }
    74→  }, [isActive]);
    75→
    76→  const completedCount = tasks.filter((t) => completedTasks.has(t.key)).length;
    77→  const allCompleted = completedCount === tasks.length;
    78→
    79→  // Trigger confetti when phase is completed
    80→  useEffect(() => {
    81→    if (allCompleted && prevCompletedCount.current < tasks.length && prevCompletedCount.current > 0) {
    82→      // Big celebration for phase completion
    83→      confetti({
    84→        particleCount: 100,
    85→        spread: 70,
    86→        origin: { y: 0.6 },
    87→        colors: ['#10b981', '#34d399', '#6ee7b7', '#fbbf24', '#f59e0b'],
    88→      });
    89→      
    90→      // Second burst
    91→      setTimeout(() => {
    92→        confetti({
    93→          particleCount: 50,
    94→          angle: 60,
    95→          spread: 55,
    96→          origin: { x: 0 },
    97→          colors: ['#10b981', '#34d399', '#6ee7b7'],
    98→        });
    99→      }, 200);
   100→      
   101→      setTimeout(() => {
   102→        confetti({
   103→          particleCount: 50,
   104→          angle: 120,
   105→          spread: 55,
   106→          origin: { x: 1 },
   107→          colors: ['#10b981', '#34d399', '#6ee7b7'],
   108→        });
   109→      }, 400);
   110→    }
   111→    prevCompletedCount.current = completedCount;
   112→  }, [allCompleted, completedCount, tasks.length]);
   113→
   114→  const handleSave = async (taskKey: string, content: string) => {
   115→    await onTaskSave(taskKey, content, phase);
   116→  };
   117→
   118→  // Get human-readable missing task names
   119→  const missingTaskNames = useMemo(() => {
   120→    return missingPhase1Tasks.map(key => taskTitleMap[key] || key);
   121→  }, [missingPhase1Tasks]);
   122→
   123→  // Build phase1Data with mvpScope if available
   124→  const enrichedPhase1Data = useMemo(() => {
   125→    const mvpScope = taskContents.get('p2_scope') || undefined;
   126→    return { ...phase1Data, mvpScope };
   127→  }, [phase1Data, taskContents]);
   128→
   129→  return (
   130→    <div
   131→      className={cn(
   132→        'border-4 border-foreground overflow-hidden',
   133→        isFuture && 'opacity-50'
   134→      )}
   135→    >
   136→      <div
   137→        className={cn(
   138→          'flex items-center justify-between p-4 transition-colors',
   139→          isActive && phaseColorClasses[phase],
   140→          isActive && 'text-white',
   141→          isPast && allCompleted && 'bg-success text-success-foreground',
   142→          isPast && !allCompleted && 'bg-secondary',
   143→          isFuture && 'bg-muted'
   144→        )}
   145→      >
   146→        <button
   147→          onClick={() => setIsOpen(!isOpen)}
   148→          className="flex items-center gap-4 text-left flex-1"
   149→        >
   150→          {isOpen ? (
   151→            <ChevronDown className="w-6 h-6" />
   152→          ) : (
   153→            <ChevronRight className="w-6 h-6" />
   154→          )}
   155→          <div>
   156→            <h3 className="font-bold text-xl">{label}</h3>
   157→            <p className="font-mono text-sm opacity-80">{description}</p>
   158→          </div>
   159→        </button>
   160→        <div className="flex items-center gap-3">
   161→          <span className="font-mono text-sm">
   162→            {completedCount}/{tasks.length}
   163→          </span>
   164→          {allCompleted && <Check className="w-6 h-6" />}
   165→        </div>
   166→      </div>
   167→
   168→      {isOpen && (
   169→        <div className="p-4 space-y-3 bg-card">
   170→          {/* Phase note at the top */}
   171→          {phaseNote && (
   172→            <div className="flex items-start gap-2 p-3 bg-muted/50 border-2 border-foreground/20 rounded mb-4">
   173→              <Info className="w-4 h-4 mt-0.5 text-muted-foreground flex-shrink-0" />
   174→              <p className="font-mono text-sm text-muted-foreground">
   175→                {phaseNote}
   176→              </p>
   177→            </div>
   178→          )}
   179→          
   180→          {tasks.map((task) => {
   181→            if (task.inputType === 'ai-generated' && task.aiConfig) {
   182→              return (
   183→                <AIGeneratedTaskItem
   184→                  key={task.key}
   185→                  id={task.key}
   186→                  title={task.title}
   187→                  description={task.description}
