    37→
    38→export function useAIGeneration() {
    39→  const [isGenerating, setIsGenerating] = useState(false);
    40→
    41→  const generate = async (
    42→    type: GeneratorType,
    43→    phase1Data: Phase1Data,
    44→    segmentData?: SegmentData,
    45→    searchFilters?: SearchFilters,
    46→    track?: string
    47→  ): Promise<string | null> => {
    48→    setIsGenerating(true);
    49→    
    50→    try {
    51→      const { data, error } = await supabase.functions.invoke('generate-startup-content', {
    52→        body: { type, phase1Data, segmentData, searchFilters, track: track || 'startup' },
    53→      });
    54→
    55→      if (error) {
    56→        console.error('AI generation error:', error);
    57→        toast.error('Failed to generate content. Please try again.');
    58→        return null;
    59→      }
    60→
    61→      if (data?.error) {
    62→        toast.error(data.error);
    63→        return null;
    64→      }
    65→
    66→      return data?.content || null;
    67→    } catch (err) {
    68→      console.error('AI generation error:', err);
    69→      toast.error('Failed to generate content. Please try again.');
    70→      return null;
    71→    } finally {
    72→      setIsGenerating(false);
    73→    }
    74→  };
    75→
    76→  return { generate, isGenerating };
    77→}
